import os, sys, traceback
import hou

def _run():
    root = hou.getenv("NIMBUS_ROOT")
    if not root:
        prefs = hou.getenv("HOUDINI_USER_PREF_DIR") or ""
        raise RuntimeError(
            "NIMBUS_ROOT is not set.\n"
            "Add a Nimbus package JSON under:\n  {0}/packages/".format(prefs)
        )
    pyroot = os.path.normpath(os.path.join(root, "scripts", "python"))
    if pyroot not in sys.path:
        sys.path.insert(0, pyroot)
    from nimbus.nimbus_menu_loader import launch
    launch("nimbus_hip_open", ("_show_dialog", "show_dialog", "main"))

try:
    _run()
except Exception:
    hou.ui.displayMessage("Nimbus Hip Open launch error:\n" + traceback.format_exc())

